{
  "project": "mms-fractal-planner",
  "architecture": "sandwich",
  "goal": "Render ALL mockups in ./design/ with Google Maps quality (60fps, zero latency)",
  "layers": {
    "engine": "Logic, Stores, Spatial Index (src/engine/)",
    "canvas": "WebGL/PixiJS rendering (src/render/)",
    "hud": "HTML/React overlays (src/components/)"
  },
  "phases": {
    "01-canvas-core": {
      "description": "WebGL canvas with Google Maps navigation (Pan/Zoom/Inertia)",
      "priority": "CRITICAL",
      "tasks": [
        { "id": "canvas-001", "name": "ViewportController", "status": "pending", "description": "Integrate pixi-viewport for pan/zoom with inertia physics" },
        { "id": "canvas-002", "name": "60fps Validation", "status": "pending", "description": "Stress test with 50k rectangles, ensure constant 60fps" },
        { "id": "canvas-003", "name": "ZoomSemantic", "status": "pending", "description": "LOD switching with hysteresis (no flicker at boundaries)" }
      ]
    },
    "02-axes-sync": {
      "description": "HTML axes perfectly synchronized with WebGL camera",
      "priority": "HIGH",
      "tasks": [
        { "id": "axes-001", "name": "TimeAxisHeader", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Top HTML ruler (Oct 1, Oct 2...) synced to canvas X position" },
        { "id": "axes-002", "name": "TrainListSidebar", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Left HTML list (T001, T002...) synced to canvas Y scroll, virtualized" },
        { "id": "axes-003", "name": "AxisScaleManager", "status": "pending", "description": "D3-scale integration for time<->pixel conversion" }
      ]
    },
    "03-heatmap-macro": {
      "description": "12-Year Heatmap visualization (LOD 0)",
      "priority": "HIGH",
      "tasks": [
        { "id": "heatmap-001", "name": "HeatmapShader", "status": "pending", "mockup": "mockup-mms-1.png", "description": "GPU shader for intensity grid (blue->orange->red)" },
        { "id": "heatmap-002", "name": "HeatmapInteraction", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Click cell to show ZoomPopup with detail preview" },
        { "id": "heatmap-003", "name": "SelectionRectangle", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Draggable selection box (blue border) on heatmap" }
      ]
    },
    "04-dnastrip-meso": {
      "description": "2-Year DNA Strip visualization (LOD 1)",
      "priority": "HIGH",
      "tasks": [
        { "id": "dna-001", "name": "DNAStripRenderer", "status": "pending", "mockup": "mockup-mms-2_2.jpg", "description": "Diagonal stripe pattern (blue/orange bars at 45deg)" },
        { "id": "dna-002", "name": "CapacityBars", "status": "pending", "mockup": "mockup-mms-5.png", "description": "Stacked bars (Mechanical blue, Electrical orange) + Capacity line" }
      ]
    },
    "05-gantt-micro": {
      "description": "4-Week Detailed Gantt visualization (LOD 2)",
      "priority": "HIGH",
      "tasks": [
        { "id": "gantt-001", "name": "TaskBlockRenderer", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Colored pills with text (MSDF/BitmapFont for crisp text)" },
        { "id": "gantt-002", "name": "DependencyLines", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Curved bezier arrows connecting tasks" },
        { "id": "gantt-003", "name": "DragDropPhysics", "status": "pending", "description": "Drag task with constraints, spring-back on invalid, snap-to-grid" },
        { "id": "gantt-004", "name": "ConflictHighlight", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Red glow/pulse on overlapping tasks" },
        { "id": "gantt-005", "name": "PitOccupancyRows", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Resource lanes (Pit 1, Pit 2, Wash Bay) below train rows" }
      ]
    },
    "06-scenario-diff": {
      "description": "Scenario comparison with ghosting and diff visualization",
      "priority": "MEDIUM",
      "tasks": [
        { "id": "scenario-001", "name": "GhostLayer", "status": "pending", "mockup": "mockup-mms-8.png", "description": "Baseline rendered at 30% opacity under active scenario" },
        { "id": "scenario-002", "name": "DiffHatching", "status": "pending", "mockup": "mockup-mms-8.png", "description": "Red diagonal hatching pattern on moved/deleted blocks" },
        { "id": "scenario-003", "name": "MoveArrows", "status": "pending", "mockup": "mockup-mms-8.png", "description": "Curved arrows showing task relocation" }
      ]
    },
    "07-hud-overlays": {
      "description": "React HUD components rendered over canvas (pointer-events: none except buttons)",
      "priority": "HIGH",
      "tasks": [
        { "id": "hud-001", "name": "AppHeader", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Fixed header: logo, title, MetricBadges (Fleet 98%, Budget On Track)" },
        { "id": "hud-002", "name": "TabBar", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Dashboard | Software | Light Mode tabs" },
        { "id": "hud-003", "name": "LegendBar", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Color legend (Routine, Mid-life, Bottlenecks)" },
        { "id": "hud-004", "name": "TaskTooltip", "status": "pending", "mockup": "mockup-mms-2_2.jpg", "description": "Hover tooltip: Task name, Duration, Resources, Cost" },
        { "id": "hud-005", "name": "ZoomPopup", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Modal: 'Zoom in 4 weeks' with mini-gantt preview" },
        { "id": "hud-006", "name": "ZoomLevelIndicator", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Dropdown: 'Micro (4 Weeks)' with zoom options" },
        { "id": "hud-007", "name": "ConflictBadge", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Red badge: 'Conflict Alerts: 0'" }
      ]
    },
    "08-sidebar": {
      "description": "Right sidebar for simulation/scenario controls",
      "priority": "MEDIUM",
      "tasks": [
        { "id": "sidebar-001", "name": "SimulationPanel", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Scenario title, Constraints section header" },
        { "id": "sidebar-002", "name": "ConstraintSlider", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Labor Availability slider (0-100%)" },
        { "id": "sidebar-003", "name": "DateRangePicker", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Date Range: Nov 01 - Nov 15" },
        { "id": "sidebar-004", "name": "InfraToggle", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Maintenance Pit Status toggle (Unavailable/Off)" },
        { "id": "sidebar-005", "name": "RunSolverButton", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Primary CTA: 'Run Solver (Est. 45s)' with icon" }
      ]
    },
    "09-timescrubber": {
      "description": "Bottom timeline navigator",
      "priority": "MEDIUM",
      "tasks": [
        { "id": "scrubber-001", "name": "MiniHeatmapPreview", "status": "pending", "mockup": "mockup-mms-2_2.jpg", "description": "Compressed 12-year heatmap as background" },
        { "id": "scrubber-002", "name": "SelectionHandle", "status": "pending", "mockup": "mockup-mms-2_2.jpg", "description": "Draggable rectangle showing current viewport" },
        { "id": "scrubber-003", "name": "ZoomButtons", "status": "pending", "mockup": "mockup-mms-6.png", "description": "1 Week | 2 Weeks | 4 Weeks | 6 Weeks quick zoom" }
      ]
    },
    "10-screens": {
      "description": "Complete screen compositions - MUST match mockups EXACTLY",
      "priority": "CRITICAL",
      "tasks": [
        { "id": "screen-001", "name": "HeatmapScreen", "status": "pending", "mockup": "mockup-mms-1.png", "description": "Header + Tabs + Heatmap(WebGL) + ZoomPopup + TimeScrubber + Legend" },
        { "id": "screen-002", "name": "MultiScaleScreen", "status": "pending", "mockup": "mockup-mms-2_2.jpg", "description": "3 stacked ViewPanels: Macro(Heatmap) + Meso(DNA) + Micro(Gantt)" },
        { "id": "screen-003", "name": "DashboardScreen", "status": "pending", "mockup": "mockup-mms-3.png", "description": "Compact 3-section layout with all visualizations" },
        { "id": "screen-004", "name": "MesoViewScreen", "status": "pending", "mockup": "mockup-mms-5.png", "description": "DNA Strip full view + Capacity Chart below" },
        { "id": "screen-005", "name": "MicroGanttScreen", "status": "pending", "mockup": "mockup-mms-6.png", "description": "Full Gantt + TrainList(left) + TimeAxis(top) + PitOccupancy" },
        { "id": "screen-006", "name": "ScenarioDiffScreen", "status": "pending", "mockup": "mockup-mms-8.png", "description": "Split/overlay view with baseline ghost + diff hatching" },
        { "id": "screen-007", "name": "SimulationScreen", "status": "pending", "mockup": "mockup-mms-10.png", "description": "Heatmap(blurred) + SimulationPanel sidebar overlay" }
      ]
    }
  },
  "dependencies_to_add": [
    "pixi-viewport (for Google Maps navigation)",
    "rbush (for spatial indexing)"
  ]
}

