     1→import { Application, Container, Graphics } from 'pixi.js';
     2→import { getViewportState, subscribeViewport, type ViewportState } from '../engine/store/viewportStore';
     3→import { getSimulationState, subscribeSimulation } from '../engine/store/simulationStore';
     4→import { HeatmapLayer } from './layers/HeatmapLayer';
     5→import { BarsLayer } from './layers/BarsLayer';
     6→import { CapsulesLayer } from './layers/CapsulesLayer';
     7→import { ViewportController } from './ViewportController';
     8→
     9→/**
    10→ * FractalRenderer - High-performance PixiJS renderer with LOD layers.
    11→ *
    12→ * Manages the PixiJS Application and three distinct rendering layers:
    13→ * - LOD 0: Heatmap (GPU shader-based)
    14→ * - LOD 1: Stacked bars (instanced rendering)
    15→ * - LOD 2: Detailed capsules with text
    16→ *
    17→ * Integrates with Zustand stores for reactive viewport/data updates.
    18→ */
    19→
    20→export interface FractalRendererConfig {
    21→  /** Row height in pixels for train lanes */
    22→  rowHeight: number;
    23→  /** Background color */
    24→  backgroundColor: number;
    25→  /** Enable debug overlay */
    26→  debug: boolean;
    27→}
    28→
    29→const DEFAULT_CONFIG: FractalRendererConfig = {
    30→  rowHeight: 40,
    31→  backgroundColor: 0x1a1a2e,
    32→  debug: false,
    33→};
    34→
    35→export class FractalRenderer {
    36→  private app: Application | null = null;
    37→  private isInitialized = false;
    38→
    39→  /** Viewport controller for pan/zoom with pixi-viewport */
    40→  private viewportController: ViewportController | null = null;
    41→
    42→  /** Layer containers for each LOD */
    43→  private lod0Container: Container | null = null;
    44→  private lod1Container: Container | null = null;
    45→  private lod2Container: Container | null = null;
    46→
    47→  /** Grid overlay for debugging */
    48→  private gridOverlay: Graphics | null = null;
    49→
    50→  /** LOD layer instances */
    51→  private heatmapLayer: HeatmapLayer | null = null;
    52→  private barsLayer: BarsLayer | null = null;
    53→  private capsulesLayer: CapsulesLayer | null = null;
    54→
    55→  /** Store unsubscribe functions */
    56→  private unsubscribeViewport: (() => void) | null = null;
    57→  private unsubscribeSimulation: (() => void) | null = null;
    58→
    59→  /** Render loop state */
    60→  private rafId: number | null = null;
    61→  private needsRender = true;
    62→
    63→  /** Configuration */
    64→  private config: FractalRendererConfig;
    65→
    66→  /** Cache for last viewport state (avoid unnecessary re-renders) */
    67→  private lastViewport: Partial<ViewportState> = {};
    68→
    69→  constructor(config: Partial<FractalRendererConfig> = {}) {
    70→    this.config = { ...DEFAULT_CONFIG, ...config };
    71→  }
    72→
    73→  /**
    74→   * Initialize the PixiJS Application and mount to container.
    75→   */
    76→  async init(container: HTMLElement): Promise<void> {
    77→    if (this.isInitialized) {
    78→      console.warn('FractalRenderer already initialized');
    79→      return;
    80→    }
    81→
    82→    // Get container dimensions before init
    83→    const rect = container.getBoundingClientRect();
    84→    const width = rect.width || 800;
    85→    const height = rect.height || 600;
    86→
    87→    // Create PixiJS Application with WebGL preference
    88→    // Note: Don't use resizeTo during init to avoid render before layers are ready
    89→    this.app = new Application();
    90→
    91→    await this.app.init({
    92→      background: this.config.backgroundColor,
    93→      width,
    94→      height,
    95→      antialias: true,
    96→      resolution: window.devicePixelRatio || 1,
    97→      autoDensity: true,
    98→      powerPreference: 'high-performance',
    99→    });
   100→
   101→    // Append canvas to container
   102→    container.appendChild(this.app.canvas);
   103→
   104→    // Set canvas style for proper sizing
   105→    this.app.canvas.style.width = '100%';
   106→    this.app.canvas.style.height = '100%';
   107→    this.app.canvas.style.display = 'block';
   108→
   109→    // Initialize viewport controller with pixi-viewport
   110→    this.viewportController = new ViewportController({
   111→      worldWidth: 200000, // ~12 years worth of content
   112→      worldHeight: 15000, // ~375 rows at 40px each
   113→      decelerate: true,
   114→      friction: 0.92,
   115→      minScale: 0.05,
   116→      maxScale: 20,
   117→      clamp: false,
   118→    });
   119→    const viewport = this.viewportController.init(this.app);
   120→    this.app.stage.addChild(viewport);
   121→
   122→    // Create layer hierarchy INSIDE the viewport (not stage)
   123→    this.createLayers(viewport);
   124→
   125→    // Subscribe to store updates
   126→    this.subscribeToStores();
   127→
   128→    // Update viewport dimensions
   129→    getViewportState().setDimensions(width, height);
   130→
   131→    // Mark as initialized before starting render loop
   132→    this.isInitialized = true;
   133→
   134→    // Start render loop
   135→    this.startRenderLoop();
   136→
   137→    console.log('[FractalRenderer] Initialized', { width, height });
   138→  }
   139→
   140→  /**
   141→   * Create container hierarchy for LOD layers inside the viewport.
   142→   */
   143→  private createLayers(parent: Container): void {
   144→    if (!this.app) return;
   145→
   146→    // LOD 0: Heatmap layer (bottom)
   147→    this.lod0Container = new Container();
   148→    this.lod0Container.label = 'lod0-heatmap';
   149→    parent.addChild(this.lod0Container);
   150→
   151→    // Initialize heatmap layer
   152→    this.heatmapLayer = new HeatmapLayer({ rowHeight: this.config.rowHeight });
   153→    this.lod0Container.addChild(this.heatmapLayer.getContainer());
   154→
   155→    // LOD 1: Bars layer (middle)
