     1→import { Container, Sprite, Texture, SCALE_MODES } from 'pixi.js';
     2→import { getSimulationState } from '../../engine/store/simulationStore';
     3→import { getViewportState } from '../../engine/store/viewportStore';
     4→
     5→/**
     6→ * HeatmapLayer - LOD 0 renderer for very zoomed out views.
     7→ *
     8→ * Aggregates schedule blocks into time buckets and renders
     9→ * density as a color heatmap using GPU-accelerated texture sampling.
    10→ *
    11→ * Performance: Pre-computes density texture once per data change,
    12→ * then renders using simple sprite with texture lookup.
    13→ */
    14→
    15→export interface HeatmapConfig {
    16→  /** Number of time buckets across viewport */
    17→  numBuckets: number;
    18→  /** Row height in pixels */
    19→  rowHeight: number;
    20→  /** Number of train rows */
    21→  numRows: number;
    22→}
    23→
    24→const DEFAULT_CONFIG: HeatmapConfig = {
    25→  numBuckets: 256,
    26→  rowHeight: 40,
    27→  numRows: 128,
    28→};
    29→
    30→/** Color palette for heatmap (cold to hot) */
    31→const HEATMAP_COLORS = [
    32→  0x1a1a2e, // 0: Empty - dark blue/purple
    33→  0x16213e, // 1: Very low
    34→  0x0f4c5c, // 2: Low - teal
    35→  0x00a896, // 3: Medium-low - cyan
    36→  0x3ddc84, // 4: Medium - green
    37→  0xffc93c, // 5: Medium-high - yellow
    38→  0xff6b35, // 6: High - orange
    39→  0xd62828, // 7: Very high - red
    40→] as const;
    41→
    42→export class HeatmapLayer {
    43→  private container: Container;
    44→  private sprite: Sprite | null = null;
    45→  private densityData: Float32Array;
    46→  private texture: Texture | null = null;
    47→  private config: HeatmapConfig;
    48→  private isDirty = true;
    49→
    50→  constructor(config: Partial<HeatmapConfig> = {}) {
    51→    this.config = { ...DEFAULT_CONFIG, ...config };
    52→    this.container = new Container();
    53→    this.container.label = 'heatmap-layer';
    54→
    55→    // Pre-allocate density array (rows × buckets)
    56→    this.densityData = new Float32Array(this.config.numRows * this.config.numBuckets);
    57→  }
    58→
    59→  /**
    60→   * Get the container for adding to stage.
    61→   */
    62→  getContainer(): Container {
    63→    return this.container;
    64→  }
    65→
    66→  /**
    67→   * Mark layer as needing recalculation.
    68→   */
    69→  markDirty(): void {
    70→    this.isDirty = true;
    71→  }
    72→
    73→  /**
    74→   * Update and render the heatmap.
    75→   */
    76→  update(): void {
    77→    if (!this.isDirty) return;
    78→
    79→    this.computeDensity();
    80→    this.updateTexture();
    81→    this.isDirty = false;
    82→  }
    83→
    84→  /**
    85→   * Compute density from schedule data.
    86→   * Aggregates blocks into time buckets per train row.
    87→   */
    88→  private computeDensity(): void {
    89→    const { schedule } = getSimulationState();
    90→    const viewport = getViewportState();
    91→    const { numBuckets, numRows } = this.config;
    92→
    93→    // Reset density array
    94→    this.densityData.fill(0);
    95→
    96→    if (schedule.count === 0) return;
    97→
    98→    // Calculate visible time range
    99→    const { originTime, scale, offsetX, width } = viewport;
   100→    const startTime = (0 - offsetX) / scale + originTime;
   101→    const endTime = (width - offsetX) / scale + originTime;
   102→    const timeRange = endTime - startTime;
   103→    const bucketDuration = timeRange / numBuckets;
   104→
   105→    // Aggregate blocks into buckets
   106→    for (let i = 0; i < schedule.count; i++) {
   107→      const blockStart = schedule.startTimes[i];
   108→      const blockEnd = schedule.endTimes[i];
   109→      const trainId = schedule.trainIds[i];
   110→
   111→      // Skip if outside visible range
   112→      if (blockEnd < startTime || blockStart > endTime) continue;
   113→
   114→      // Skip if train is out of range
   115→      if (trainId < 0 || trainId >= numRows) continue;
   116→
   117→      // Calculate bucket range for this block
   118→      const startBucket = Math.max(0, Math.floor((blockStart - startTime) / bucketDuration));
   119→      const endBucket = Math.min(numBuckets - 1, Math.floor((blockEnd - startTime) / bucketDuration));
   120→
   121→      // Increment density for each affected bucket
   122→      for (let b = startBucket; b <= endBucket; b++) {
   123→        const idx = trainId * numBuckets + b;
   124→        this.densityData[idx]++;
   125→      }
   126→    }
   127→  }
   128→
   129→  /**
   130→   * Update the texture from density data.
   131→   */
   132→  private updateTexture(): void {
   133→    const { numBuckets, numRows, rowHeight } = this.config;
   134→    const viewport = getViewportState();
   135→
   136→    // Find max density for normalization
   137→    let maxDensity = 1;
   138→    for (let i = 0; i < this.densityData.length; i++) {
   139→      if (this.densityData[i] > maxDensity) {
   140→        maxDensity = this.densityData[i];
   141→      }
   142→    }
   143→
   144→    // Create RGBA pixel data
   145→    const pixelData = new Uint8Array(numBuckets * numRows * 4);
   146→
   147→    for (let row = 0; row < numRows; row++) {
   148→      for (let bucket = 0; bucket < numBuckets; bucket++) {
   149→        const density = this.densityData[row * numBuckets + bucket];
   150→        const normalizedDensity = density / maxDensity;
   151→
   152→        // Map to color index (0-7)
   153→        const colorIdx = Math.min(7, Math.floor(normalizedDensity * 8));
   154→        const color = HEATMAP_COLORS[colorIdx];
   155→
   156→        // Extract RGB components
   157→        const r = (color >> 16) & 0xff;
   158→        const g = (color >> 8) & 0xff;
   159→        const b = color & 0xff;
   160→
   161→        // Write to pixel array
   162→        const pixelIdx = (row * numBuckets + bucket) * 4;
   163→        pixelData[pixelIdx] = r;
   164→        pixelData[pixelIdx + 1] = g;
   165→        pixelData[pixelIdx + 2] = b;
   166→        pixelData[pixelIdx + 3] = 255;
   167→      }
   168→    }
   169→
   170→    // Destroy old texture
   171→    if (this.texture) {
   172→      this.texture.destroy(true);
   173→    }
   174→
   175→    // Create new texture from pixel data
   176→    this.texture = Texture.from({
   177→      resource: pixelData,
   178→      width: numBuckets,
   179→      height: numRows,
   180→      scaleMode: SCALE_MODES.NEAREST,
   181→    });
   182→
   183→    // Update or create sprite
   184→    if (this.sprite) {
   185→      this.sprite.texture = this.texture;
   186→    } else {
   187→      this.sprite = new Sprite(this.texture);
   188→      this.container.addChild(this.sprite);
   189→    }
   190→
   191→    // Scale sprite to fill viewport
   192→    this.sprite.width = viewport.width;
   193→    this.sprite.height = numRows * rowHeight;
   194→  }
   195→
   196→  /**
   197→   * Resize the layer.
   198→   */
   199→  resize(width: number, _height: number): void {
   200→    if (this.sprite) {
   201→      this.sprite.width = width;
   202→      // Height stays based on numRows × rowHeight
   203→    }
   204→    this.markDirty();
   205→  }
   206→
   207→  /**
   208→   * Destroy the layer and release resources.
   209→   */
   210→  destroy(): void {
   211→    if (this.texture) {
   212→      this.texture.destroy(true);
   213→      this.texture = null;
   214→    }
   215→
   216→    if (this.sprite) {
   217→      this.sprite.destroy();
   218→      this.sprite = null;
