import { Container, Graphics } from 'pixi.js';

/**
 * StressTestLayer - Renders 50k+ rectangles to validate 60fps performance.
 *
 * Uses PixiJS batch rendering for optimal GPU performance.
 * Rectangles are distributed across the world space with random colors.
 */

export interface StressTestConfig {
  /** Number of rectangles to render */
  count: number;
  /** World width in pixels */
  worldWidth: number;
  /** World height in pixels */
  worldHeight: number;
  /** Rectangle width */
  rectWidth: number;
  /** Rectangle height */
  rectHeight: number;
}

const DEFAULT_CONFIG: StressTestConfig = {
  count: 50000,
  worldWidth: 200000,
  worldHeight: 15000,
  rectWidth: 80,
  rectHeight: 30,
};

/** Color palette for stress test rectangles */
const COLORS = [
  0x4ecdc4, // teal
  0xff6b6b, // red
  0x45b7d1, // blue
  0xfeca57, // yellow
  0xff9ff3, // pink
  0x54a0ff, // light blue
  0x5f27cd, // purple
  0x00d2d3, // cyan
  0xf368e0, // magenta
  0x10ac84, // green
];

interface RectData {
  x: number;
  y: number;
  width: number;
  height: number;
  color: number;
}

export class StressTestLayer {
  private container: Container;
  private graphics: Graphics;
  private config: StressTestConfig;
  private rects: RectData[] = [];
  private isDirty = true;
  private isGenerated = false;

  constructor(config: Partial<StressTestConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.container = new Container();
    this.container.label = 'stress-test-layer';

    // Use a single Graphics object for batch rendering
    this.graphics = new Graphics();
    this.container.addChild(this.graphics);
  }

  /**
   * Get the container for adding to stage.
   */
  getContainer(): Container {
    return this.container;
  }

  /**
   * Mark layer as needing redraw.
   */
  markDirty(): void {
    this.isDirty = true;
  }

  /**
   * Generate random rectangles distributed across world space.
   */
  generateRects(): void {
    if (this.isGenerated) return;

    const { count, worldWidth, worldHeight, rectWidth, rectHeight } = this.config;

    this.rects = [];

    // Use seeded random for consistent results
    let seed = 12345;
    const random = () => {
      seed = (seed * 1103515245 + 12345) & 0x7fffffff;
      return seed / 0x7fffffff;
    };

    for (let i = 0; i < count; i++) {
      const x = random() * (worldWidth - rectWidth);
      const y = random() * (worldHeight - rectHeight);
      const color = COLORS[Math.floor(random() * COLORS.length)];

      this.rects.push({
        x,
        y,
        width: rectWidth + random() * 40 - 20, // Vary width slightly
        height: rectHeight + random() * 10 - 5, // Vary height slightly
        color,
      });
    }

    this.isGenerated = true;
    this.isDirty = true;

    console.log(`[StressTestLayer] Generated ${count} rectangles`);
  }

  /**
   * Update and render the stress test.
   */
  update(): void {
    if (!this.isGenerated) {
      this.generateRects();
    }

    if (!this.isDirty) return;

    this.render();
    this.isDirty = false;
  }

  /**
   * Render all rectangles using batch drawing.
   */
  private render(): void {
    this.graphics.clear();

    // Draw all rectangles in a single batch
    for (const rect of this.rects) {
      this.graphics.rect(rect.x, rect.y, rect.width, rect.height);
      this.graphics.fill({ color: rect.color, alpha: 0.8 });
    }
  }

  /**
   * Get the number of rectangles.
   */
  getCount(): number {
    return this.rects.length;
  }

  /**
   * Destroy the layer and release resources.
   */
  destroy(): void {
    this.graphics.destroy();
    this.container.destroy({ children: true });
    this.rects = [];
  }
}

