import type { Meta, StoryObj } from '@storybook/react';
import Box from '@mui/material/Box';
import { StressTestCanvas } from '../StressTestCanvas';
import ThemeProvider from '../../theme/ThemeProvider';

/**
 * 60fps Validation Stress Test
 *
 * Tests PixiJS rendering performance with large numbers of rectangles.
 * Target: maintain constant 60fps during pan/zoom operations.
 */
const meta: Meta<typeof StressTestCanvas> = {
  title: 'Render/StressTest',
  component: StressTestCanvas,
  decorators: [
    (Story) => (
      <ThemeProvider>
        <Box sx={{ width: '100vw', height: '100vh', bgcolor: 'background.default' }}>
          <Story />
        </Box>
      </ThemeProvider>
    ),
  ],
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component: '60fps stress test with configurable rectangle count. Validates WebGL batch rendering performance.',
      },
    },
  },
};

export default meta;
type Story = StoryObj<typeof StressTestCanvas>;

/**
 * Standard stress test with 50,000 rectangles.
 * This is the target for canvas-002 validation.
 */
export const Default: Story = {
  args: {
    rectCount: 50000,
    showFps: true,
  },
};

/**
 * Light stress test with 10,000 rectangles.
 * Good for baseline performance comparison.
 */
export const Light10k: Story = {
  args: {
    rectCount: 10000,
    showFps: true,
  },
};

/**
 * Medium stress test with 25,000 rectangles.
 */
export const Medium25k: Story = {
  args: {
    rectCount: 25000,
    showFps: true,
  },
};

/**
 * Heavy stress test with 100,000 rectangles.
 * Tests maximum performance capacity.
 */
export const Heavy100k: Story = {
  args: {
    rectCount: 100000,
    showFps: true,
  },
};

/**
 * Extreme stress test with 200,000 rectangles.
 * Push the limits of WebGL batch rendering.
 */
export const Extreme200k: Story = {
  args: {
    rectCount: 200000,
    showFps: true,
  },
};

